import { serve } from 'https://deno.land/std@0.168.0/http/server.ts';
import { createClient } from 'https://esm.sh/@supabase/supabase-js@2';
import { verifyMessage } from 'https://esm.sh/viem@1';

const { message, signature, address } = await req.json();
const recovered = await verifyMessage({ message, signature, address });
if (!recovered) return new Response('Invalid signature', { status: 400 });

Extract nonce from message string (parse 'Nonce: {nonce}' line).
const { data: nonceRow } = await adminSupabase.from('siwe_nonces').select('*').eq('nonce', nonce).eq('address', address).single();
if (!nonceRow || nonceRow.used || new Date(nonceRow.expires_at) < new Date()) { return new Response('Invalid or expired nonce', { status: 400 }); }
await adminSupabase.from('siwe_nonces').update({ used: true }).eq('nonce', nonce);

const walletEmail = address.toLowerCase() + '@wallet.flatfinder.app';
const { data: existingUser } = await adminSupabase.auth.admin.listUsers();
const user = existingUser.users.find(u => u.email === walletEmail);
if (!user) { await adminSupabase.auth.admin.createUser({ email: walletEmail, email_confirm: true, user_metadata: { wallet_address: address } }); }
const { data: linkData } = await adminSupabase.auth.admin.generateLink({ type: 'magiclink', email: walletEmail });
return new Response(JSON.stringify({ url: linkData.properties.action_link }), { headers: { 'Content-Type': 'application/json' } });
